import re

with open('/tmp/alb-data/ALB-073.txt', 'r') as f:
    content = f.read()

# Find all rounds
round_pattern = re.compile(r'\[USER\]: Round (\d+): Guess (.+?)(?:\n|$)')
rounds = round_pattern.findall(content)

# For each round, find the Base Stats value in the feedback
# Base Stats appears between the round header and the next [USER] or [FINAL QUESTION]
results = []
for i, (round_num, guess) in enumerate(rounds):
    # Find the section for this round
    start = content.find(f'[USER]: Round {round_num}:')
    if i + 1 < len(rounds):
        end = content.find(f'[USER]: Round {int(round_num)+1}:', start)
        if end == -1:
            # Try next round number
            for j, (rn, _) in enumerate(rounds):
                if int(rn) > int(round_num):
                    end = content.find(f'[USER]: Round {rn}:', start)
                    break
    else:
        end = content.find('[FINAL QUESTION]', start)
    if end == -1:
        end = len(content)

    section = content[start:end]

    # Find Base Stats line
    bs_match = re.search(r'Base Stats:\s*(\d+)', section)
    if bs_match:
        val = int(bs_match.group(1))
        results.append((int(round_num), guess.strip(), val))
    else:
        results.append((int(round_num), guess.strip(), None))

# Find the max
valid = [(r, g, v) for r, g, v in results if v is not None]
valid.sort(key=lambda x: x[2], reverse=True)
print("Top 10 rounds by base stats:")
for r, g, v in valid[:10]:
    print(f"  Round {r}: {g} - {v}")

print(f"\nMax: Round {valid[0][0]} with value {valid[0][2]}")
