import re
import json

with open('/tmp/alb-data/ALB-077.txt', 'r') as f:
    content = f.read()

user_pattern = re.compile(r'\[USER\]: Round (\d+):')
user_matches = list(user_pattern.finditer(content))
tool_pattern = re.compile(r'\[TOOL RESULT\]:')
tool_matches = list(tool_pattern.finditer(content))

# For round 8 and 25, find the tool result before the round header
for target_round in [8, 25]:
    user_match = None
    for m in user_matches:
        if int(m.group(1)) == target_round:
            user_match = m
            break

    nearest_tool = None
    for t in tool_matches:
        if t.start() < user_match.start():
            nearest_tool = t
        else:
            break

    json_start = nearest_tool.end()
    brace_count = 0
    json_end = json_start
    in_string = False
    escape = False
    for i in range(json_start, len(content)):
        c = content[i]
        if escape:
            escape = False
            continue
        if c == '\\':
            escape = True
            continue
        if c == '"' and not escape:
            in_string = not in_string
        if not in_string:
            if c == '{':
                brace_count += 1
            elif c == '}':
                brace_count -= 1
                if brace_count == 0:
                    json_end = i + 1
                    break

    json_str = content[json_start:json_end]
    data = json.loads(json_str)

    # The "intersection" in this format is the intersection of all sections' candidates
    # Compute it: intersection of all candidates lists across per_section
    all_candidates_sets = []
    for section in data.get('per_section', []):
        candidates = section.get('candidates', [])
        all_candidates_sets.append(set(candidates))

    if all_candidates_sets:
        intersection = set.intersection(*all_candidates_sets)
        print(f"Round {target_round}: computed intersection has {len(intersection)} Pokemon")
        if 'Cascoon' in intersection:
            print(f"  Cascoon IS in round {target_round} tool result intersection")
        else:
            print(f"  Cascoon is NOT in round {target_round} tool result intersection")
    else:
        print(f"Round {target_round}: no per_section data")

