import re, json

with open('/tmp/alb-data/ALB-095.txt', 'r') as f:
    text = f.read()

# Parse rounds more carefully
# Find all [USER]: Round N: Guess ... lines
user_starts = [(m.start(), m.group(1), m.group(2)) for m in re.finditer(r'\[USER\]: Round (\d+): Guess (.+?) \(#(\d+)\)', text)]

# For each round, extract feedback sections and tool result
for idx, (start, name, num) in enumerate(user_starts):
    end = user_starts[idx+1][0] if idx+1 < len(user_starts) else len(text)
    round_text = text[start:end]

    # Find [TOOL RESULT] JSON
    tool_match = re.search(r'\[TOOL RESULT\].*?(\{.*?\})', round_text, re.DOTALL)
    intersection = []
    if tool_match:
        try:
            data = json.loads(tool_match.group(1))
            intersection = data.get('intersection', [])
        except:
            pass

    # Find all (correct) annotations in feedback sections
    correct_props = []
    for line in round_text.split('\n'):
        if '(correct)' in line:
            correct_props.append(line.strip())

    print(f"=== Round {idx+1}: {name} ===")
    if correct_props:
        for p in correct_props:
            print(f"  CORRECT: {p}")
    if intersection:
        print(f"  INTERSECTION ({len(intersection)}): {intersection}")
    print()
